UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('21bd7e91-cadf-4faf-bded-75eb139b8831'::uuid, 'Pour un cœur et des vaisseaux sains, la vitamine D3 contribue au maintien des fonctions immunitaires et à la santé osseuse.'),('f00403ea-749a-4369-b0e7-fe014c204f9e'::uuid, 'Face au stress physiologique, le magnésium B6 aide à diminuer la fatigue et l''anxiété.'),('6a147aa0-6632-4e66-8d42-5816a605e49a'::uuid, 'Le corps peut être sollicité, les probiotiques rééquilibrent la flore intestinale pour un soutien digestif et immunitaire optimal.'),('e81bd5ff-61f5-4e16-afad-5abef2b4dcbe'::uuid, 'Un transit lent peut entraîner des selles dures, le psyllium blond augmente le volume des selles pour faciliter leur évacuation.'),('f1012775-9764-49f3-9161-e8a9ce2ce57b'::uuid, 'Un transit intestinal ralenti peut causer une gêne, les fibres prébiotiques nourrissent la flore pour stimuler l''activité intestinale.'),('7d45d0c1-aa02-47e0-bebe-799de8994f10'::uuid, 'Un transit intestinal lent provoque une constipation, le psyllium blond augmente le volume des selles pour régulariser le rythme digestif.'),('d6ce15b8-3cf1-4809-a5cb-8faca5b778f5'::uuid, 'Les carences peuvent impacter la régulation de l''humeur, les multivitamines soutiennent les fonctions neurologiques pour une meilleure stabilité émotionnelle.'),('303f188d-c367-4b36-ba7d-a42d41cfae35'::uuid, 'La multiplicité des médicaments peut rendre la prise complexe, un pilulier semainier aide à organiser le traitement pour éviter les oublis.'),('93842c21-b2f1-43ca-8fd4-8d9e899b88e2'::uuid, 'Les variations d''humeur sont fréquentes, un carnet de suivi permet d''identifier les facteurs déclenchants pour mieux gérer les épisodes.'),('a5d4585b-3baa-4e6f-8058-71cf107856f8'::uuid, 'Le trouble panique peut épuiser l''organisme, les multivitamines apportent des nutriments essentiels pour soutenir le système nerveux.'),('a65b2b9e-f402-497f-a0fc-b782a10306b4'::uuid, 'L''anxiété augmente la consommation de magnésium, le magnésium B6 aide à réguler le système nerveux pour diminuer les manifestations du trouble panique.'),('ae40c1d8-e802-440d-a6dd-3899a2507a3e'::uuid, 'L''axe intestin-cerveau est impliqué, les probiotiques rééquilibrent la flore intestinale pour apaiser le système nerveux et réduire l''anxiété.'),('33aea834-6788-4c33-b7fc-a003fc61218c'::uuid, 'Le stress peut amplifier les symptômes, le magnésium B6 aide à réguler le système nerveux et diminuer la fatigue physique.'),('0fd53a16-4083-46e9-bdc2-873bd45ed263'::uuid, 'La fatigue nerveuse peut être intense, le magnésium B6 soutient les fonctions psychologiques et réduit l''épuisement.'),('6b6780f7-8ac9-4495-853e-8bc4b40ec115'::uuid, 'Les épisodes peuvent générer de l''anxiété, le magnésium B6 contribue à l''équilibre nerveux et à une meilleure gestion du stress.'),('9152f425-32c0-4a6c-9624-c348bef1c2ab'::uuid, 'Les fonctions cognitives peuvent être diminuées, les multivitamines apportent des nutriments essentiels au bon fonctionnement cérébral.'),('a0342cdd-538c-4a4b-adc4-78438037b8f9'::uuid, 'La Rhodiola Rosea aide l''organisme à s''adapter au stress mental, améliorant ainsi la concentration et la vivacité d''esprit.'),('2392c873-230c-4ce1-bf4b-e655a27739aa'::uuid, 'La fatigue mentale peut altérer la vigilance, le Ginseng rouge stimule l''activité neuronale pour améliorer la mémoire et la concentration.'),('41180623-b19d-4eb4-9368-e37d04b026aa'::uuid, 'Une désynchronisation du rythme circadien perturbe le sommeil, la mélatonine régule le cycle veille-sommeil pour un endormissement plus rapide.'),('79e1ffcc-ef4b-465a-b56d-04c12c725357'::uuid, 'Le stress et l''anxiété rendent l''endormissement difficile, l''Euphytose agit sur le système nerveux pour favoriser la relaxation et le sommeil.'),('88236722-7ce4-4ff0-8df8-e54facf00f88'::uuid, 'La tension nerveuse et musculaire affecte la qualité du sommeil, le magnésium favorise la détente pour un repos réparateur.'),('054912eb-9fa3-46fd-b95a-97abc784a4da'::uuid, 'Les troubles prostatiques augmentent le risque d''infection urinaire, l''extrait de Cranberry acidifie les urines pour prévenir la fixation bactérienne.'),('e4a21036-4ffd-4390-bc3c-96dfe741b326'::uuid, 'Une prostate sensible peut augmenter les risques infectieux, l''extrait de Cranberry contribue à assainir l''appareil urinaire et réduire les bactéries.'),('d09356bf-1b07-4ed0-bf31-008593910ee9'::uuid, 'Les troubles prostatiques peuvent favoriser les infections, l''extrait de Cranberry aide à prévenir la prolifération bactérienne dans les voies urinaires.'),('a73a629c-584d-493c-8139-8741e9cb351e'::uuid, 'L''urticaire est une réaction allergique, l''antihistaminique bloque l''histamine pour apaiser le prurit et réduire les lésions cutanées.'),('48cc1e39-ecac-459a-95b3-f856f3f89bb6'::uuid, 'Les démangeaisons intenses de l''urticaire irritent la peau, cette crème apaise l''épiderme pour réduire rapidement la sensation de prurit.'),('39214eb3-6f21-4fcd-88f0-2224e1e03a7e'::uuid, 'La peau est enflammée et irritée, l''eau thermale en spray calme les sensations désagréables et décongestionne l''épiderme.'),('4f8c07c2-c072-4f15-84d1-f5ff86d53fb1'::uuid, 'La vaccination mobilise le système immunitaire, la vitamine D3 renforce les défenses naturelles pour une meilleure réponse.'),('c8612e1c-84f7-4a66-8d17-58153fcd5746'::uuid, 'Pour optimiser la réponse immunitaire après la vaccination, la vitamine D3 soutient le fonctionnement des cellules immunitaires.'),('b116ca13-0560-4df1-8e98-5c8c4b2d3a2b'::uuid, 'La vaccination stimule le corps, la vitamine D3 aide à moduler la réponse immunitaire pour soutenir l''organisme.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;